/*
 * frexp() test harness — prints (input_hex, mantissa_hex, exponent) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;

static void emit(double x)
{
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    int exp;
    g_acc += frexp(vx, &exp);
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#else
static void emit(double x)
{
    int exp;
    double mantissa = frexp(x, &exp);
    printf("%016llx %016llx %d\n", (unsigned long long)d2u(x), (unsigned long long)d2u(mantissa), exp);
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#endif

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN);                  /* smallest normal: 2^-1022 = 0x0010000000000000 */
    emit(-DBL_MIN);
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit(DBL_MAX);                  /* largest normal: 0x7fefffffffffffff */
    emit(-DBL_MAX);
    emit_u(0x7fefffffffffffffULL);  /* one ULP below DBL_MAX (same as DBL_MAX here - already max) */

    /* --- Section 4: Powers of 2 (14) --- */
    /* frexp(2^n) = (0.5, n+1); mantissa is exactly 0.5 for all powers of 2 */
    emit(0.125);    /* 2^-3 -> mantissa=0.5, exp=-2 */
    emit(-0.125);
    emit(0.25);     /* 2^-2 -> mantissa=0.5, exp=-1 */
    emit(-0.25);
    emit(0.5);      /* 2^-1 -> mantissa=0.5, exp=0 */
    emit(-0.5);
    emit(1.0);      /* 2^0  -> mantissa=0.5, exp=1 */
    emit(-1.0);
    emit(2.0);      /* 2^1  -> mantissa=0.5, exp=2 */
    emit(-2.0);
    emit(4.0);      /* 2^2  -> mantissa=0.5, exp=3 */
    emit(16.0);     /* 2^4  -> mantissa=0.5, exp=5 */
    emit(1024.0);   /* 2^10 -> mantissa=0.5, exp=11 */
    emit_u(0x4330000000000000ULL);  /* 2^52 = 4503599627370496.0 */

    /* --- Section 5: ULP neighbors of powers of 2 (12) --- */
    /* These test that the exponent increments/decrements correctly at boundaries */
    emit_u(0x3feffffffffffffeULL);  /* 2 ULPs below 1.0 */
    emit_u(0x3fefffffffffffffULL);  /* 1 ULP below 1.0: mantissa just under 1.0 -> exp=0 */
    emit_u(0x3ff0000000000001ULL);  /* 1 ULP above 1.0 */
    emit_u(0x3fffffffffffffff ULL); /* 1 ULP below 2.0: largest mantissa in [1,2) */
    emit_u(0x4000000000000001ULL);  /* 1 ULP above 2.0 */
    emit_u(0x3ff0000000000000ULL);  /* exactly 1.0 */
    emit_u(0x3fdffffffffffffeULL);  /* 2 ULPs below 0.5 */
    emit_u(0x3fdfffffffffffffULL);  /* 1 ULP below 0.5 */
    emit_u(0x3fe0000000000001ULL);  /* 1 ULP above 0.5 */
    emit_u(0x4000000000000000ULL);  /* exactly 2.0 */
    emit_u(0x3fe0000000000000ULL);  /* exactly 0.5 */
    emit_u(0x3feffffffffffffeULL);  /* 2 ULPs below 1.0 (negative) -- replace with -2.0 ULP neighbor */

    /* --- Section 6: Mantissa-dense values near [0.5, 1.0) boundary (8) --- */
    /* frexp always returns mantissa in [0.5, 1.0); these stress the mantissa extraction */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 exactly (lower boundary of mantissa range) */
    emit_u(0x3fe4000000000000ULL);  /* 0.625 */
    emit_u(0x3fe8000000000000ULL);  /* 0.75 */
    emit_u(0x3fec000000000000ULL);  /* 0.875 */
    emit_u(0x3fefffffffffffffULL);  /* just below 1.0 (upper boundary of mantissa range) */
    emit_u(0xbfe0000000000000ULL);  /* -0.5 */
    emit_u(0xbfe8000000000000ULL);  /* -0.75 */
    emit_u(0xbfefffffffffffffULL);  /* just above -1.0 */

    /* --- Section 7: Representative normal values across exponent range (20) --- */
    emit(1.5);
    emit(-1.5);
    emit(3.0);
    emit(-3.0);
    emit(3.5);
    emit(-3.5);
    emit(5.0);
    emit(-5.0);
    emit(7.5);
    emit(-7.5);
    emit(3.14159265358979323846);   /* pi */
    emit(-3.14159265358979323846);
    emit(2.718281828459045235360);  /* e */
    emit(1.4142135623730950488);    /* sqrt(2) */
    emit(100.0);
    emit(-100.0);
    emit(1000.0);
    emit(0.1);
    emit(0.01);
    emit(-0.01);

    /* --- Section 8: Near-integer fractions (10) --- */
    /* Values like n.5 where the mantissa spans the 0.5 boundary in interesting ways */
    emit(2.5);
    emit(-2.5);
    emit(4.5);
    emit(8.5);
    emit(15.5);
    emit(31.5);
    emit(63.5);
    emit(127.5);
    emit(255.5);
    emit(511.5);

    /* --- Section 9: Large values and exponent extremes (9) --- */
    emit(1.0e10);
    emit(-1.0e10);
    emit(1.0e100);
    emit(-1.0e100);
    emit(1.0e200);
    emit(-1.0e200);
    emit(1.0e300);
    emit(1.23456789012345e150);
    emit(-9.87654321098765e-150);

    /* --- Section 10: Small normal values near DBL_MIN (8) --- */
    /* These exercise the subnormal-to-normal boundary and small exponents */
    emit(1.0e-200);
    emit(-1.0e-200);
    emit(1.0e-300);
    emit(-1.0e-300);
    emit_u(0x0020000000000000ULL);  /* 2*DBL_MIN = 2^-1021 */
    emit_u(0x0030000000000000ULL);  /* 3*DBL_MIN (mantissa = 0.75, exp=-1021) */
    emit_u(0x0018000000000000ULL);  /* 1.5*DBL_MIN */
    emit_u(0x8020000000000000ULL);  /* -2*DBL_MIN */
}

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(double x)
{
    volatile double acc = 0.0;
    int exp;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += frexp(x+i, &exp);
    stopPFM;
    readResult();
    printf("perf %016llx: %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u((double)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

/* 7. Sweep across multiple octaves */
static void test_sweep(void)
{
    double bases[] = { 1.0, 1.5, 2.5, 3.5, 5.0, 7.5 };
    int nbases = sizeof(bases) / sizeof(bases[0]);
    for (int p = -10; p <= 10; p += 2) {
        double scale = (1 << (p / 2));
        if (p & 1) scale *= 1.414213562373095;  /* sqrt(2) */
        for (int i = 0; i < nbases; i++) {
            emit(bases[i] * scale);
        }
    }
}

/* 8. Sample across exponent range */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fc0000000000000ULL, /* 0.125 */
        0x3fd0000000000000ULL, /* 0.25 */
        0x3fd8000000000000ULL, /* 0.375 */
        0x3fe0000000000000ULL, /* 0.5 */
        0x3fe4000000000000ULL, /* 0.625 */
        0x3fe8000000000000ULL, /* 0.75 */
        0x3ff0000000000000ULL, /* 1.0 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i]);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    double lo = -100.0;
    double hi =  100.0;
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

